// Simple Node.js pseudocode: idempotent join endpoint for signaling
const express = require('express');
const app = express();
app.use(express.json());
// In-memory idempotency store for demo; use Redis or DB in prod
const idempotency = new Map();

app.post('/join', (req, res) => {
  const key = req.headers['idempotency-key'];
  if (!key) return res.status(400).send({ error: 'Missing Idempotency Key' });

  if (idempotency.has(key)) {
    // Return cached response to avoid duplicate work
    return res.json(idempotency.get(key));
  }

  // Example join handling: auth, allocate SFU slot, return PoP info
  const body = req.body;
  // ... auth and validation omitted
  const response = {
    meetingId: body.meetingId,
    pop: chooseBestPoP(req.ip),
    token: issueShortLivedToken(body.userId)
  };

  idempotency.set(key, response);
  // Set TTL in real store; here omitted
  res.json(response);
});

app.listen(8080);
